def heuristic_crypto_pipeline_failure_warning(today_stats: dict) -> tuple[bool, str]:
    """Emit PIPELINE_WARN when BTC or ETH RSI is <=20 but no crypto trade fired in 7d."""
    rsi_snapshot = today_stats.get("rsi_snapshot", {})
    btc_rsi = rsi_snapshot.get("BTC/USD", {}).get("today", 100)
    eth_rsi = rsi_snapshot.get("ETH/USD", {}).get("today", 100)
    if btc_rsi > 20 and eth_rsi > 20:
        return False, ""
    by_strategy = today_stats.get("by_strategy", {})
    crypto_trades_7d = sum(
        by_strategy.get(s, {}).get("trades_7d", 0)
        for s in ("crypto-momentum", "crypto-oversold-bounce", "crypto-breakdown")
    )
    if crypto_trades_7d > 0:
        return False, ""
    return True, (
        f"CRYPTO_PIPELINE_WARN — BTC/USD RSI={btc_rsi:.1f}, ETH/USD RSI={eth_rsi:.1f} "
        f"(ekstremalna wyprzedaz) ale 0 krypto-trade w 7d. "
        "Sprawdz: crypto-monitor workflow logs, Cloudflare Worker health, "
        "Alpaca API creds, predator-bracket filter vs aktualny 24h move."
    )

