class TestCryptoPipelineFailureWarning(unittest.TestCase):
    def test_fires_when_both_extreme_no_trades(self):
        stats = {
            "rsi_snapshot": {"BTC/USD": {"today": 11.8}, "ETH/USD": {"today": 14.6}},
            "by_strategy": {}
        }
        fired, reason = heuristic_crypto_pipeline_failure_warning(stats)
        self.assertTrue(fired)
        self.assertIn("CRYPTO_PIPELINE_WARN", reason)
        self.assertIn("11.8", reason)

    def test_no_fire_when_both_rsi_normal(self):
        stats = {
            "rsi_snapshot": {"BTC/USD": {"today": 45.0}, "ETH/USD": {"today": 38.0}},
            "by_strategy": {}
        }
        fired, _ = heuristic_crypto_pipeline_failure_warning(stats)
        self.assertFalse(fired)

    def test_no_fire_when_crypto_trades_present(self):
        stats = {
            "rsi_snapshot": {"BTC/USD": {"today": 11.8}, "ETH/USD": {"today": 14.6}},
            "by_strategy": {"crypto-oversold-bounce": {"trades_7d": 1}}
        }
        fired, _ = heuristic_crypto_pipeline_failure_warning(stats)
        self.assertFalse(fired)

    def test_no_fire_on_missing_rsi_data(self):
        stats = {"by_strategy": {}}
        fired, _ = heuristic_crypto_pipeline_failure_warning(stats)
        self.assertFalse(fired)
